const b64 = s => Buffer.from(s).toString('base64url');
const jwtSign = p => { const h=b64(JSON.stringify({alg:'HS256',typ:'JWT'})); const b=b64(JSON.stringify({...p,exp:Math.floor(Date.now()/1000)+604800})); const s=crypto.createHmac('sha256',SECRET).update(`${h}.${b}`).digest('base64url'); return `${h}.${b}.${s}`; };
const jwtVerify = token => { const [h,b,s]=(token||'').split('.'); if(!h||!b||!s) throw new Error('Invalid'); if(crypto.createHmac('sha256',SECRET).update(`${h}.${b}`).digest('base64url')!==s) throw new Error('Bad'); const p=JSON.parse(Buffer.from(b,'base64url').toString()); if(p.exp<Date.now()/1000) throw new Error('Expired'); return p; };
const hashPw = pw => { const salt=crypto.randomBytes(16).toString('hex'); return `${salt}:${crypto.pbkdf2Sync(pw,salt,10000,32,'sha256').toString('hex')}`; };
const verifyPw = (pw,stored) => { const [salt,hash]=stored.split(':'); return crypto.pbkdf2Sync(pw,salt,10000,32,'sha256').toString('hex')===hash; };
const uid = () => crypto.randomBytes(6).toString('hex');

